import{c as a,Q as s,j as t,m as r}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Features, embeddings, and tags","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/features-embeddings-tags.md","filePath":"concepts/features-embeddings-tags.md","lastUpdated":null}'),i={name:"concepts/features-embeddings-tags.md"};function n(o,e,d,l,c,p){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="features-embeddings-and-tags" tabindex="-1">Features, embeddings, and tags <a class="header-anchor" href="#features-embeddings-and-tags" aria-label="Permalink to &quot;Features, embeddings, and tags&quot;">​</a></h1><p>Audience: users comparing analysis families<br> Goal: separate the project data types clearly<br> Type: explanation</p><p>The app stores several kinds of information. They look similar in the UI, but they are not interchangeable.</p><h2 id="file-tags" tabindex="-1">File tags <a class="header-anchor" href="#file-tags" aria-label="Permalink to &quot;File tags&quot;">​</a></h2><p>Tags come from the audio file metadata: title, artist, album, BPM, key, and other human-facing fields. Scan and RefreshTags read a fixed practical whitelist into SQLite.</p><p>For Smart Set Builder, tag BPM is preferred when present. SONARA BPM is a fallback.</p><h2 id="sonara-features" tabindex="-1">SONARA features <a class="header-anchor" href="#sonara-features" aria-label="Permalink to &quot;SONARA features&quot;">​</a></h2><p>SONARA writes feature values, model metadata, and derived working fields such as BPM, key, duration, and energy into SQLite. These are analyzed values, not file tags copied back to audio.</p><h2 id="embeddings" tabindex="-1">Embeddings <a class="header-anchor" href="#embeddings" aria-label="Permalink to &quot;Embeddings&quot;">​</a></h2><p>MERT, CLAP, and MAEST store vector embeddings in SQLite. Search and SET can use these vectors as similarity signals.</p><p>MAEST also produces genre analysis, but SET selection should not rely on MAEST genre labels. MAEST embeddings are a different signal.</p><h2 id="classifier-scores" tabindex="-1">Classifier scores <a class="header-anchor" href="#classifier-scores" aria-label="Permalink to &quot;Classifier scores&quot;">​</a></h2><p>Promoted classifier profiles write scores to <code>track_classifier_scores</code>. A score belongs to one classifier key. Missing classifier scores are neutral for SET.</p><h2 id="reports-and-exports" tabindex="-1">Reports and exports <a class="header-anchor" href="#reports-and-exports" aria-label="Permalink to &quot;Reports and exports&quot;">​</a></h2><p>Reports, playlists, and helper-tool output are local files. They are not the same thing as library state and can usually be regenerated.</p>',15)])])}const u=a(i,[["render",n]]);export{h as __pageData,u as default};
